query:
{
  managedIdentities(
    where: {
      OR: [
        {
          vms_SOME: {
            networkInterfaces_SOME: {
              NOT: { publicIp: null }
              securityGroups_SOME: {
                rules_SOME: {
                  direction: { eq: "Inbound" }
                  action: { eq: "Allow" }
                  OR: [
                    { sources_INCLUDES: "cidr:0.0.0.0/0" }
                    { sources_INCLUDES: "cidr:::/0" }
                    { sources_INCLUDES: "tag:Internet" }
                    { sources: { eq: [] } }
                  ]
                }
              }
            }
          }
        }
        {
          functions_SOME: {
            bindings_SOME: {
              direction: { eq: "in" }
              type: { eq: "httpTrigger" }
              authLevel: { eq: "anonymous" }
            }
          }
        }
        {
          appServices_SOME: {
            OR: [
              { authSettings: null }
              { authSettings: { NOT: { enabled: { eq: true } } } }
            ]
          }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
